import 'package:flutter/material.dart';import '../services/api_service.dart';import '../widgets/app_sidebar.dart';
class TrainerBoosterScreen extends StatefulWidget{const TrainerBoosterScreen({super.key});@override State<TrainerBoosterScreen> createState()=>_State();}
class _State extends State<TrainerBoosterScreen>{final api=ApiService();bool loading=true;List<Map<String,dynamic>> questions=[],linked=[],available=[];String? error;@override void initState(){super.initState();load();}Future<void> load()async{try{final d=await api.getTrainerBooster();questions=List<Map<String,dynamic>>.from(d['questions']??const[]);linked=List<Map<String,dynamic>>.from(d['linked_quizzes']??const[]);available=List<Map<String,dynamic>>.from(d['available_quizzes']??const[]);error=null;}catch(e){error=e.toString();}if(mounted)setState(()=>loading=false);}Future<void> add()async{final q=TextEditingController();final opts=List.generate(4,(_)=>TextEditingController());int correct=0;final ok=await showDialog<bool>(context:context,builder:(c)=>StatefulBuilder(builder:(c,setLocal)=>AlertDialog(title:const Text('Add booster question'),content:SizedBox(width:520,child:ListView(shrinkWrap:true,children:[TextField(controller:q,decoration:const InputDecoration(labelText:'Question')),...opts.asMap().entries.map((e)=>RadioListTile<int>(value:e.key,groupValue:correct,onChanged:(v)=>setLocal(()=>correct=v!),title:TextField(controller:e.value,decoration:InputDecoration(labelText:'Option ${e.key+1}'))))])),actions:[TextButton(onPressed:()=>Navigator.pop(c,false),child:const Text('Cancel')),FilledButton(onPressed:()async{if(q.text.trim().isEmpty||opts.any((o)=>o.text.trim().isEmpty))return;await api.createBoosterQuestion({'text':q.text.trim(),'image_path':null,'options':opts.asMap().entries.map((e)=>{'text':e.value.text.trim(),'is_correct':e.key==correct}).toList()});if(c.mounted)Navigator.pop(c,true);},child:const Text('Save'))])));if(ok==true){loading=true;load();}}@override Widget build(BuildContext context)=>Scaffold(drawer:const AppSidebar(role:'trainer'),appBar:AppBar(title:const Text('Brain Booster Questions'),actions:[IconButton(onPressed:load,icon:const Icon(Icons.refresh))]),floatingActionButton:FloatingActionButton.extended(onPressed:add,icon:const Icon(Icons.add),label:const Text('Add question')),body:loading?const Center(child:CircularProgressIndicator()):error!=null?Center(child:Text(error!)):ListView(padding:const EdgeInsets.all(20),children:[const Text('Question pool',style:TextStyle(fontSize:22,fontWeight:FontWeight.bold)),...questions.map((q)=>Card(child:ListTile(title:Text(q['text'].toString()),subtitle:Text(List<Map<String,dynamic>>.from(q['options']).map((o)=>'${o['is_correct']==true?'✓':'•'} ${o['text']}').join('\n')),trailing:IconButton(onPressed:()async{await api.deleteBoosterQuestion(q['id'] as int);load();},icon:const Icon(Icons.delete_outline))))),const SizedBox(height:20),const Text('Linked quiz pools',style:TextStyle(fontSize:22,fontWeight:FontWeight.bold)),...linked.map((q)=>ListTile(title:Text(q['title'].toString()),trailing:IconButton(onPressed:()async{await api.unlinkBoosterQuiz(q['id'] as int);load();},icon:const Icon(Icons.link_off)))),if(available.isNotEmpty)DropdownButtonFormField<int>(decoration:const InputDecoration(labelText:'Link another quiz'),items:available.map((q)=>DropdownMenuItem(value:q['id'] as int,child:Text(q['title'].toString()))).toList(),onChanged:(id)async{if(id!=null){await api.linkBoosterQuiz(id);load();}})]));}
